import{_ as e,o as n,c as s,ag as l}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"RAII Model in Vex","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/RAII_Model.md","filePath":"archive/extra/RAII_Model.md"}'),o={name:"archive/extra/RAII_Model.md"};function i(p,a,t,r,c,d){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="raii-model-in-vex" tabindex="-1">RAII Model in Vex <a class="header-anchor" href="#raii-model-in-vex" aria-label="Permalink to &quot;RAII Model in Vex&quot;">​</a></h1><p>Vex implements <strong>RAII (Resource Acquisition Is Initialization)</strong> using a <strong>Rust-like</strong> approach combined with <strong>Go&#39;s <code>defer</code> keyword</strong>. This model ensures safe, predictable, and automatic resource management.</p><hr><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><ol><li><strong>Automatic Cleanup</strong>: Resources are automatically cleaned up when they go out of scope.</li><li><strong>Deterministic</strong>: Cleanup happens at a known point (end of scope).</li><li><strong>Explicit Control</strong>: <code>defer</code> allows manual scheduling of cleanup logic.</li></ol><hr><h2 id="the-drop-contract" tabindex="-1">The <code>Drop</code> Contract <a class="header-anchor" href="#the-drop-contract" aria-label="Permalink to &quot;The \`Drop\` Contract&quot;">​</a></h2><p>The <code>Drop</code> contract is central to Vex&#39;s RAII.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>contract Drop {</span></span>
<span class="line"><span>    /// Called automatically at scope exit</span></span>
<span class="line"><span>    fn drop(self: &amp;Self!);</span></span>
<span class="line"><span>}</span></span></code></pre></div><ul><li><strong>Automatic Call</strong>: Called when variable goes out of scope.</li><li><strong>Mutable Receiver</strong>: <code>&amp;Self!</code> allows modification during cleanup (e.g., setting file handle to -1).</li><li><strong>Compiler Injection</strong>: Calls are injected implicitly by the compiler.</li></ul><hr><h2 id="example-file-resource" tabindex="-1">Example: File Resource <a class="header-anchor" href="#example-file-resource" aria-label="Permalink to &quot;Example: File Resource&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct File {</span></span>
<span class="line"><span>    fd: i32,</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>impl Drop for File {</span></span>
<span class="line"><span>    fn drop(self: &amp;File!) {</span></span>
<span class="line"><span>        println(f&quot;Closing file {self.fd}&quot;);</span></span>
<span class="line"><span>        syscall_close(self.fd);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn process() {</span></span>
<span class="line"><span>    let f = File { fd: 10 };</span></span>
<span class="line"><span>    // do work...</span></span>
<span class="line"><span>    // f.drop() called here automatically</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="interaction-with-defer" tabindex="-1">Interaction with <code>defer</code> <a class="header-anchor" href="#interaction-with-defer" aria-label="Permalink to &quot;Interaction with \`defer\`&quot;">​</a></h2><p>Vex allows <code>defer</code> for ad-hoc cleanup, often used when valid RAII types aren&#39;t available or for logic flow.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn complex_logic() {</span></span>
<span class="line"><span>    let temp = TemporaryFile.new(); // Implements Drop</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    defer println(&quot;Function finished&quot;);  // Runs last</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // ... logic</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>} // temp.drop() runs, then &quot;Function finished&quot; prints.</span></span></code></pre></div><p><strong>Order of Operations:</strong></p><ol><li>Scope-based <code>Drop</code> calls (LIFO).</li><li><code>defer</code> statements (LIFO). (Note: Exact ordering between Drop and Defer needs strict specification, usually Defer runs before local drops in Go/Zig, but Vex treats them similarly).</li></ol><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Vex&#39;s RAII model combines Rust&#39;s safety (Drop trait) with Go&#39;s pragmatism (Defer), providing ergonomic resource management.</p>`,22)])])}const m=e(o,[["render",i]]);export{u as __pageData,m as default};
